import{_ as t,o,c as i,a3 as a}from"./chunks/framework.BTFg6ESq.js";const p=JSON.parse('{"title":"贡献指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/contribution-guide.md","filePath":"guide/contribution-guide.md","lastUpdated":1764526901000}'),r={name:"guide/contribution-guide.md"};function l(n,e,s,c,d,u){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="贡献指南" tabindex="-1">贡献指南 <a class="header-anchor" href="#贡献指南" aria-label="Permalink to &quot;贡献指南&quot;">​</a></h1><p>欢迎为 AIO Hub 做出贡献！为了保持代码质量和协作效率，请遵循以下规范。</p><h2 id="_1-代码规范" tabindex="-1">1. 代码规范 <a class="header-anchor" href="#_1-代码规范" aria-label="Permalink to &quot;1. 代码规范&quot;">​</a></h2><h3 id="_1-1-typescript-javascript" tabindex="-1">1.1 TypeScript / JavaScript <a class="header-anchor" href="#_1-1-typescript-javascript" aria-label="Permalink to &quot;1.1 TypeScript / JavaScript&quot;">​</a></h3><ul><li><strong>Linter</strong>: 项目使用 ESLint 和 Prettier。提交前请确保代码通过检查。</li><li><strong>类型安全</strong>: 避免使用 <code>any</code>，除非万不得已。尽量定义清晰的 Interface 或 Type。</li><li><strong>命名</strong>: <ul><li>变量/函数: <code>camelCase</code></li><li>类/组件: <code>PascalCase</code></li><li>常量: <code>UPPER_SNAKE_CASE</code></li></ul></li></ul><h3 id="_1-2-vue-组件" tabindex="-1">1.2 Vue 组件 <a class="header-anchor" href="#_1-2-vue-组件" aria-label="Permalink to &quot;1.2 Vue 组件&quot;">​</a></h3><ul><li><strong>Composition API</strong>: 统一使用 <code>&lt;script setup lang=&quot;ts&quot;&gt;</code>。</li><li><strong>组件名</strong>: 多单词组合，如 <code>UserProfile.vue</code>。</li><li><strong>Props</strong>: 必须定义类型。</li></ul><h2 id="_2-git-工作流" tabindex="-1">2. Git 工作流 <a class="header-anchor" href="#_2-git-工作流" aria-label="Permalink to &quot;2. Git 工作流&quot;">​</a></h2><p>我们采用简化的 GitHub Flow。</p><ol><li><strong>Fork</strong> 仓库。</li><li>基于 <code>main</code> 分支创建你的特性分支: <code>git checkout -b feature/my-new-feature</code>。</li><li>提交更改。</li><li>推送到你的 Fork。</li><li>发起 <strong>Pull Request</strong> 到 <code>main</code> 分支。</li></ol><h2 id="_3-commit-message-规范" tabindex="-1">3. Commit Message 规范 <a class="header-anchor" href="#_3-commit-message-规范" aria-label="Permalink to &quot;3. Commit Message 规范&quot;">​</a></h2><p>请遵循 <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a> 规范。</p><p>格式: <code>&lt;type&gt;(&lt;scope&gt;): &lt;subject&gt;</code></p><ul><li><strong>feat</strong>: 新功能</li><li><strong>fix</strong>: 修复 Bug</li><li><strong>docs</strong>: 文档变更</li><li><strong>style</strong>: 代码格式（不影响逻辑）</li><li><strong>refactor</strong>: 代码重构</li><li><strong>perf</strong>: 性能优化</li><li><strong>test</strong>: 测试相关</li><li><strong>chore</strong>: 构建过程或辅助工具的变动</li></ul><p>示例: <code>feat(llm-chat): add support for deepseek model</code></p><h2 id="_4-开发环境" tabindex="-1">4. 开发环境 <a class="header-anchor" href="#_4-开发环境" aria-label="Permalink to &quot;4. 开发环境&quot;">​</a></h2><ol><li>安装依赖: <code>bun install</code></li><li>启动开发服务器: <code>bun run tauri dev</code></li><li>构建生产版本: <code>bun run tauri build</code></li></ol><h2 id="_5-报告问题" tabindex="-1">5. 报告问题 <a class="header-anchor" href="#_5-报告问题" aria-label="Permalink to &quot;5. 报告问题&quot;">​</a></h2><p>如果你发现了 Bug 或有新功能建议，请在 GitHub Issues 中提交。请提供清晰的复现步骤和环境信息。</p>',19)])])}const h=t(r,[["render",l]]);export{p as __pageData,h as default};
